from __future__ import annotations


def external_sources_dashboard_html() -> str:
    return r'''<!doctype html><html lang="ru"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>External Data Sources — AI-BIT</title><style>
:root{color-scheme:light;--bg:#f5f6f8;--surface:#fff;--line:#e3e6ea;--text:#17191c;--muted:#70757d;--accent:#5e6ad2;--ok:#16835d;--warn:#a9670b;--bad:#b42318;--mono:ui-monospace,SFMono-Regular,Consolas,monospace}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:13px/1.45 Inter,Segoe UI,sans-serif}main{max-width:1500px;margin:auto;padding:24px 26px 80px}.header{display:flex;justify-content:space-between;gap:20px;align-items:flex-start;margin-bottom:14px}.eyebrow{font-size:10px;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--accent)}h1{font-size:25px;margin:4px 0}.muted{color:var(--muted)}.actions{display:flex;gap:8px}.btn{border:1px solid var(--line);background:#fff;border-radius:7px;padding:8px 11px;cursor:pointer}.btn.primary{background:#202124;color:#fff;border-color:#202124}.policy{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:12px}.chip{background:#fff;border:1px solid var(--line);border-radius:999px;padding:5px 9px;font:11px var(--mono)}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}.card{background:#fff;border:1px solid var(--line);border-radius:10px;overflow:hidden}.card-head{padding:12px 14px;border-bottom:1px solid var(--line);display:flex;justify-content:space-between;gap:10px;background:#fafbfc}.card-body{padding:13px 14px}.row{display:grid;grid-template-columns:170px minmax(0,1fr);gap:10px;padding:7px 0;border-bottom:1px solid #eef0f2}.row:last-child{border:0}.label{color:var(--muted)}.mono{font-family:var(--mono);font-size:11px;word-break:break-all}.badge{border-radius:999px;padding:3px 7px;font-size:10px;font-weight:800;text-transform:uppercase}.ok{background:#e7f6ef;color:var(--ok)}.partial{background:#fff3dc;color:var(--warn)}.not_configured,.error{background:#fee4e2;color:var(--bad)}pre{margin:0;white-space:pre-wrap;max-height:420px;overflow:auto}.empty{padding:30px;text-align:center;color:var(--muted);background:#fff;border:1px solid var(--line);border-radius:10px}@media(max-width:850px){.grid{grid-template-columns:1fr}.header{display:block}.actions{margin-top:10px}.row{grid-template-columns:1fr}}
</style></head><body><main><div class="header"><div><div class="eyebrow">External Data Sources</div><h1>Источники данных</h1><div class="muted">1С HTTP и MCP · единый evidence-формат · без изменений исходных систем</div></div><div class="actions"><button class="btn" id="status">Статус</button><button class="btn primary" id="collect">Собрать evidence</button></div></div><div id="policy" class="policy"></div><div id="content"><div class="empty">Загрузка конфигурации источников…</div></div></main><script>
(()=>{'use strict';const q=s=>document.querySelector(s);const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));function badge(v){const x=String(v||'not_configured').toLowerCase();return `<span class="badge ${esc(x)}">${esc(x)}</span>`}function render(data){const p=data.execution_policy||{};q('#policy').innerHTML=[`mode: ${data.mode||'read_only'}`,`HTTP: ${(p.http_methods||[]).join(', ')||'GET'}`,`MCP write tools: ${p.mcp_write_tools_allowed===false?'blocked':'unknown'}`,`automatic changes: ${p.automatic_changes===false?'disabled':'unknown'}`].map(x=>`<span class="chip">${esc(x)}</span>`).join('');const rows=data.providers||[];q('#content').innerHTML=rows.length?`<div class="grid">${rows.map(x=>`<section class="card"><div class="card-head"><div><b>${esc(x.id)}</b><div class="muted mono">${esc(x.type)}</div></div>${badge(x.status||(x.configured?'configured':'not_configured'))}</div><div class="card-body"><div class="row"><span class="label">Configured</span><span>${x.configured?'yes':'no'}</span></div><div class="row"><span class="label">Endpoint</span><span class="mono">${esc(x.base_url||x.url||'')}</span></div><div class="row"><span class="label">Read only</span><span>${x.read_only?'yes':'no'}</span></div><div class="row"><span class="label">Errors</span><span class="mono">${esc((x.errors||[]).length)}</span></div>${x.objects?`<div class="row"><span class="label">HTTP objects</span><pre class="mono">${esc(JSON.stringify(x.objects,null,2))}</pre></div>`:''}${x.tools?`<div class="row"><span class="label">MCP tools</span><pre class="mono">${esc(JSON.stringify(x.tools,null,2))}</pre></div>`:''}</div></section>`).join('')}</div>`:'<div class="empty">Источники не зарегистрированы.</div>'}async function load(url,method='GET'){const target=method==='POST'?q('#collect'):q('#status');target.disabled=true;try{const r=await fetch(url,{method,cache:'no-store'});if(!r.ok)throw new Error(await r.text());render(await r.json())}catch(e){q('#content').innerHTML=`<div class="empty">Ошибка: ${esc(e.message)}</div>`}finally{target.disabled=false}}q('#status').onclick=()=>load('/external-sources/status?_='+Date.now());q('#collect').onclick=()=>load('/external-sources/collect','POST');load('/external-sources/latest?_='+Date.now());})();
</script></body></html>'''
